// =========================================================================
// framePr (§17.3.1.11) — Text Frame Properties
// =========================================================================

/// ISO 29500-1 §17.3.1.11: w:framePr defines text frame properties
/// (width, height, anchors, wrap, position). Its presence marks a
/// paragraph as part of a text frame.
///
/// Fixture: frame-pr
///   P0: framePr with w=2191, h=811, hRule=exact, hSpace=180,
///       wrap=around, vAnchor=text, hAnchor=page, x=1921
///   P1: normal paragraph (no frame)
#[test]
fn pa08_frame_pr_preserved() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "frame-pr");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "expected at least 2 paragraphs, got {}",
        paras.len()
    );

    let frame = paras[0]
        .frame_pr
        .as_ref()
        .expect("P0 should have frame properties");
    assert_eq!(frame.width, Some(2191));
    assert_eq!(frame.height, Some(811));
    assert_eq!(frame.h_rule, Some(stemma::domain::HeightRule::Exact));
    assert_eq!(frame.h_space, Some(180));
    assert_eq!(frame.wrap, Some(stemma::domain::FrameWrap::Around));
    assert_eq!(frame.v_anchor, Some(stemma::domain::VAnchor::Text));
    assert_eq!(frame.h_anchor, Some(stemma::domain::HAnchor::Page));
    assert_eq!(frame.x, Some(1921));

    assert!(paras[1].frame_pr.is_none(), "P1: no frame");
}

// =========================================================================
// bidi + mirrorIndents interaction
// =========================================================================

/// ISO 29500-1 §17.3.1.6 + §17.3.1.18: bidi and mirrorIndents together.
///
/// When both bidi and mirrorIndents are set, indentation behavior becomes
/// complex: bidi reverses start/end semantics, and mirrorIndents swaps
/// indents on even pages.
///
/// Fixture: bidi-mirror-indents
///   P0: bidi + mirrorIndents + start=1440, end=720
///   P1: bidi only + start=1440, end=720
///   P2: mirrorIndents only + start=1440, end=720
#[test]
fn pa09_bidi_plus_mirror_indents() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "bidi-mirror-indents");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "expected at least 3 paragraphs, got {}",
        paras.len()
    );

    // mirrorIndents is parsed, so we can verify those parts:
    assert_eq!(paras[0].mirror_indents, Some(true), "P0: mirrorIndents on");
    assert_eq!(
        paras[1].mirror_indents, None,
        "P1: no mirrorIndents (bidi only)"
    );
    assert_eq!(paras[2].mirror_indents, Some(true), "P2: mirrorIndents on");

    // bidi assertions:
    assert_eq!(paras[0].bidi, Some(true), "P0: bidi on");
    assert_eq!(paras[1].bidi, Some(true), "P1: bidi on");
    assert_eq!(paras[2].bidi, None, "P2: bidi absent");
}

// =========================================================================
// Multiple boolean properties combined
// =========================================================================

/// ISO 29500-1 §17.3.1: Multiple boolean paragraph properties combined.
///
/// Fixture: combined-booleans
///   P0: suppressAutoHyphens=true, snapToGrid=false, overflowPunct=false,
///       adjustRightInd=false, wordWrap=false
///   P1: all defaults (control)
#[test]
fn pa10_combined_boolean_properties() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "combined-booleans");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "expected at least 2 paragraphs, got {}",
        paras.len()
    );

    // P0: all set
    assert_eq!(paras[0].suppress_auto_hyphens, Some(true));
    assert_eq!(paras[0].snap_to_grid, Some(false));
    assert_eq!(paras[0].overflow_punct, Some(false));
    assert_eq!(paras[0].adjust_right_ind, Some(false));
    assert_eq!(paras[0].word_wrap, Some(false));

    // P1 (control): all None
    assert_eq!(paras[1].suppress_auto_hyphens, None);
    assert_eq!(paras[1].snap_to_grid, None);
    assert_eq!(paras[1].overflow_punct, None);
    assert_eq!(paras[1].adjust_right_ind, None);
    assert_eq!(paras[1].word_wrap, None);
}

// =========================================================================
// POSITIVE: Fixture files load without errors
// =========================================================================

/// Smoke test: all paragraph audit fixtures import without panicking.
///
/// This verifies that the DOCX files are valid and our importer handles
/// the unknown properties gracefully (even if it drops them).
#[test]
fn pa_smoke_all_fixtures_import() {
    let fixtures = [
        "bidi",
        "text-alignment",
        "suppress-auto-hyphens",
        "snap-to-grid",
        "overflow-punct",
        "adjust-right-ind",
        "word-wrap",
        "frame-pr",
        "bidi-mirror-indents",
        "combined-booleans",
    ];

    for name in &fixtures {
        let (_runtime, doc) = common::import_fixture(FIXTURES, name);
        let paras = common::all_paragraphs(&doc);
        assert!(
            !paras.is_empty(),
            "fixture '{name}' should have at least one paragraph"
        );
    }
}

/// Positive test: mirrorIndents IS parsed on the bidi-mirror-indents fixture.
///
/// This documents that mirrorIndents (§17.3.1.18) works correctly even when
/// combined with other properties that are not yet parsed.
#[test]
fn pa_positive_mirror_indents_parsed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "bidi-mirror-indents");
    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 3,
        "expected at least 3 paragraphs, got {}",
        paras.len()
    );

    // P0: bidi + mirrorIndents — mirrorIndents should be true
    assert_eq!(
        paras[0].mirror_indents,
        Some(true),
        "P0: mirrorIndents on (bidi + mirrorIndents)"
    );

    // P1: bidi only — no mirrorIndents
    assert_eq!(
        paras[1].mirror_indents, None,
        "P1: mirrorIndents absent (bidi only)"
    );

    // P2: mirrorIndents only
    assert_eq!(paras[2].mirror_indents, Some(true), "P2: mirrorIndents on");

    // Indentation should be preserved on all three
    for (i, p) in paras.iter().take(3).enumerate() {
        let ind = p
            .indent
            .as_ref()
            .unwrap_or_else(|| panic!("P{i}: should have indent"));
        assert_eq!(
            ind.left,
            Some(1440),
            "P{i}: left indent should be 1440 (from start=1440)"
        );
        assert_eq!(
            ind.right,
            Some(720),
            "P{i}: right indent should be 720 (from end=720)"
        );
    }
}
